1658	func scoreSearchCandidates(candidates []searchCandidate, q searchQuery, fileDF map[string]int, fileCount int) {
1659		if len(candidates) == 0 {
1660			return
1661		}
1662		averageLength := 0.0
1663		for _, candidate := range candidates {
1664			averageLength += float64(maxInt(1, candidate.docLength))
1665		}
1666		averageLength /= float64(len(candidates))
1667		queryWeight := 0.0
1668		idf := make(map[string]float64, len(q.terms))
1669		for _, term := range q.terms {
1670			df := fileDF[term]
1671			weight := math.Log(1+(float64(fileCount-df)+0.5)/(float64(df)+0.5)) * q.weights[term]
1672			idf[term] = weight
1673			queryWeight += weight
1674		}
1675		for i := range candidates {
1676			candidate := &candidates[i]
1677			bm25 := 0.0
1678			coveredWeight := 0.0
1679			codeTokenBonus := 0.0
1680			for _, term := range q.terms {
1681				frequency := candidate.termCounts[term]
1682				if frequency == 0 {
1683					continue
1684				}
1685				weight := idf[term]
1686				coveredWeight += weight
1687				if q.weights[term] >= 2 {
1688					codeTokenBonus += 6 * q.weights[term]
1689				}
1690				denominator := float64(frequency) + 1.2*(0.25+0.75*float64(maxInt(1, candidate.docLength))/averageLength)
1691				bm25 += weight * (float64(frequency) * 2.2 / denominator)
1692			}
1693			coverage := 0.0
1694			if queryWeight > 0 {
1695				coverage = coveredWeight / queryWeight
1696			}
1697			candidate.score = candidate.baseScore + bm25 + 7*coverage + minFloat64(24, codeTokenBonus)
1698			if codeTokenBonus > 0 {
1699				candidate.result.Signals = appendUnique(candidate.result.Signals, "exact-code-token")
1700			}
1701			if coverage == 1 {
1702				candidate.score += 2
1703				candidate.result.Signals = appendUnique(candidate.result.Signals, "all-query-terms")
1704			}
1705		}
1706	}
