// checkQuorum validates that enough providers succeeded to meet quorum and AZ
// coverage requirements. Returns nil if the quorum is met.
//
// Requirements:
//   - At least minQuorumProviders must be present and minQuorumSuccesses must succeed
//   - All providers must have AZ information configured
//   - Successful providers must span at least minQuorumAZs distinct AZs
func checkQuorum(outcomes []providerOutcome) *QuorumError {
	if len(outcomes) < minQuorumProviders {
		return &QuorumError{
			Reason:    "insufficient providers",
			Providers: len(outcomes),
		}
	}

	// Count distinct AZs across ALL resolved providers (including failed).
	allAZs := make(map[string]struct{})
	for _, o := range outcomes {
		if o.az != "" {
			allAZs[o.az] = struct{}{}
		}
	}
	distinctAZs := len(allAZs)

	// Count successful providers and their AZs.
	var succeeded int
	successAZs := make(map[string]struct{})
	for _, o := range outcomes {
		if !o.failed {
			succeeded++
			if o.az != "" {
				successAZs[o.az] = struct{}{}
			}
		}
	}
	nSuccessAZs := len(successAZs)

	var reason string
	switch {
	case succeeded < minQuorumSuccesses:
		reason = "insufficient successful providers"
	case distinctAZs == 0:
		reason = "no AZ information configured on providers"
	case nSuccessAZs < minQuorumAZs:
		reason = "insufficient AZ coverage"
	default:
		return nil
	}

	return &QuorumError{
		Reason:      reason,
		Providers:   len(outcomes),
		Succeeded:   succeeded,
		DistinctAZs: distinctAZs,
		SuccessAZs:  nSuccessAZs,
	}
}

