2438	func selectDiverseCandidates(candidates []searchCandidate, topK, maxPerFile int) []searchCandidate {
2439		remaining := append([]searchCandidate(nil), candidates...)
2440		selected := make([]searchCandidate, 0, minInt(topK, len(remaining)))
2441		perFile := map[string]int{}
2442		perSymbolName := map[string]int{}
2443		perBaseName := map[string]int{}
2444		distinctFileTarget := minInt(topK, (topK+1)/2)
2445		for len(selected) < topK {
2446			// Search is primarily a discovery operation for coding agents. Give the
2447			// agent one strong location from each candidate file before spending the
2448			// remaining result budget on additional regions in files it has already
2449			// seen. Without this first pass, a few large or repetitive files can fill
2450			// the context window even when other relevant implementation files ranked
2451			// close behind them. The reserve is relevance-bounded: an exact usage or
2452			// second requested symbol must not be buried under weak matches merely
2453			// because it shares a file with an earlier result.
2454			fileLimit := maxPerFile
2455			if len(perFile) < distinctFileTarget && shouldReserveUnseenSearchFile(
2456				remaining, selected, perFile, perSymbolName, perBaseName, maxPerFile,
2457			) {
2458				fileLimit = 1
2459			}
2460			bestIndex := -1
2461			bestAdjusted := -math.MaxFloat64
2462			for i := range remaining {
2463				candidate := remaining[i]
2464				if perFile[candidate.result.FilePath] >= fileLimit || overlapsSelected(candidate, selected) {
2465					continue
2466				}
2467				adjusted := adjustedSearchCandidateScore(candidate, perFile, perSymbolName, perBaseName)
2468				if adjusted > bestAdjusted || (adjusted == bestAdjusted && searchCandidateLess(candidate, remaining[bestIndex])) {
2469					bestIndex = i
2470					bestAdjusted = adjusted
2471				}
2472			}
2473			if bestIndex < 0 {
2474				break
2475			}
2476			selected = append(selected, remaining[bestIndex])
2477			chosen := remaining[bestIndex].result
2478			perFile[chosen.FilePath]++
2479			symbolKey := strings.ToLower(chosen.QualifiedName)
2480			if symbolKey == "" {
2481				symbolKey = strings.ToLower(chosen.SymbolName)
2482			}
2483			if symbolKey != "" {
2484				perSymbolName[symbolKey]++
2485			}
2486			perBaseName[strings.ToLower(filepath.Base(chosen.FilePath))]++
2487			remaining = append(remaining[:bestIndex], remaining[bestIndex+1:]...)
2488		}
2489		return selected
2490	}
