2494		perFile, perSymbolName, perBaseName map[string]int,
2495		maxPerFile int,
2496	) bool {
2497		bestAny := -math.MaxFloat64
2498		bestUnseen := -math.MaxFloat64
2499		bestRelationship := -math.MaxFloat64
2500		for _, candidate := range candidates {
2501			if perFile[candidate.result.FilePath] >= maxPerFile || overlapsSelected(candidate, selected) {
2502				continue
2503			}
